// server-v2.ts (conceptual)
function finalizeBrowserOutput(baseText, browserPayload) {
  const host = extractHost(browserPayload?.url);
  const shortcuts = getSiteShortcuts(host);
  if (!shortcuts?.length) return baseText ?? "";

  const block = formatShortcutBlock(host, shortcuts);
  if ((baseText ?? "").includes("⌨️ SITE SHORTCUTS")) return baseText;
  return baseText && baseText.trim().length > 0
    ? `${baseText}\n\n${block}`
    : block;
}

